import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Platform Release — v1.1.0","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Platform Release — v1.1.0 | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/changelog/v1.1.0"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Platform Release — v1.1.0 | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/changelog/v1.1.0"}]]},"headers":[],"relativePath":"changelog/v1.1.0.md","filePath":"changelog/v1.1.0.md","lastUpdated":1784743690000}'),i={name:"changelog/v1.1.0.md"};function n(l,e,d,s,c,g){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="platform-release-—-v1-1-0" tabindex="-1">Platform Release — v1.1.0 <a class="header-anchor" href="#platform-release-—-v1-1-0" aria-label="Permalink to &quot;Platform Release — v1.1.0&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td><strong>Release tag</strong></td><td><code>v1.1.0</code></td></tr><tr><td><strong>Release date</strong></td><td>TBD — create GitHub Releases only after all three repos are merged and CI is green on <code>main</code></td></tr><tr><td><strong>Platform status</strong></td><td>Production Ready / Stabilized</td></tr><tr><td><strong>Scope</strong></td><td>First official platform tag: foundation (auth, tenancy, RBAC, marketplace, billing, Leads/Tasks) + post-freeze stabilization (multi-provider email, hardening, notifications, Communication Templates, Larastan zero-debt, CI quality gates)</td></tr></tbody></table><p>This is the official <strong>first tagged</strong> platform release. Earlier docs referred to a logical freeze as <code>v1.1.0-platform</code>; <strong>no git tags existed</strong>. Per semantic versioning policy, the coordinated tag is clean <strong><code>v1.1.0</code></strong> (no suffixes).</p><p><strong>Do not create git tags or GitHub Releases until:</strong> Backend, Frontend, and Docs are merged to <code>main</code>, Quality Gates are green, and operators have reviewed this document.</p><hr><h2 id="versioning" tabindex="-1">Versioning <a class="header-anchor" href="#versioning" aria-label="Permalink to &quot;Versioning&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Artifact</th><th>Version</th></tr></thead><tbody><tr><td>Coordinated git tag (all three repos)</td><td><code>v1.1.0</code></td></tr><tr><td>SaaS-Frontend <code>package.json</code></td><td><code>1.1.0</code></td></tr><tr><td>SaaS-Docs <code>package.json</code></td><td><code>1.1.0</code></td></tr><tr><td>SaaS-Backend</td><td>Tag-only (no Composer <code>version</code> field)</td></tr></tbody></table><p>Policy: <strong>clean Semantic Versioning only</strong> (<code>vMAJOR.MINOR.PATCH</code>). Do not use suffixes such as <code>-platform</code>, <code>-stable</code>, or <code>-release</code>.</p><hr><h2 id="compatibility" tabindex="-1">Compatibility <a class="header-anchor" href="#compatibility" aria-label="Permalink to &quot;Compatibility&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Requirement</th></tr></thead><tbody><tr><td>PHP</td><td>8.3+ (CI: <strong>8.4</strong>)</td></tr><tr><td>Laravel</td><td>13.x</td></tr><tr><td>Node.js</td><td>20+ (CI: latest LTS)</td></tr><tr><td>Frontend</td><td>React 19 SPA</td></tr><tr><td>Databases</td><td>MySQL/MariaDB or SQLite (tests) per environment</td></tr><tr><td>Queues</td><td>Redis recommended; workers must include <code>emails,default</code></td></tr><tr><td>Realtime</td><td>Laravel Reverb (notifications) optional but recommended</td></tr></tbody></table><hr><h2 id="what-s-included" tabindex="-1">What’s included <a class="header-anchor" href="#what-s-included" aria-label="Permalink to &quot;What’s included&quot;">​</a></h2><h3 id="platform-foundation" tabindex="-1">Platform foundation <a class="header-anchor" href="#platform-foundation" aria-label="Permalink to &quot;Platform foundation&quot;">​</a></h3><ul><li>Authentication (Central + Tenant), tenancy, Spatie RBAC + <code>module:{slug}</code> licensing</li><li>Marketplace, billing ledger, payment gateways (Stripe + Manual / Creem path)</li><li>Settings hierarchy, audit/activity logging, impersonation</li><li>Reference modules: <strong>Leads</strong>, <strong>Tasks</strong></li><li>Architecture freeze — see <a href="/getting-started/platform-freeze">Platform Freeze</a></li></ul><h3 id="stabilization-this-milestone" tabindex="-1">Stabilization (this milestone) <a class="header-anchor" href="#stabilization-this-milestone" aria-label="Permalink to &quot;Stabilization (this milestone)&quot;">​</a></h3><ul><li><strong>Multi-provider email</strong> — <code>EmailManager</code>, SMTP/Postmark/Mailgun, Central + Tenant modes, logs, queue isolation</li><li><strong>Production hardening</strong> — migrate-only modules/RBAC, auth≠RBAC, go-live runbooks</li><li><strong>Notifications</strong> — digests, prune, Reverb/Echo ops</li><li><strong>Communication Templates</strong> — platform module with data-migration registration</li><li><strong>Larastan level 5</strong> — zero errors (typing/PHPDoc only; no behavior change)</li><li><strong>CI standardization</strong> — PR Quality Gates on Backend / Frontend / Docs; artifact publish on <code>main</code> only</li></ul><hr><h2 id="breaking-changes" tabindex="-1">Breaking changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking changes&quot;">​</a></h2><p>Relative to pre-marketplace / plan-based licensing:</p><ol><li>Plans / Features / usage limits removed — licensing is module subscriptions only.</li><li>Central SPA routes under <code>/central/*</code>.</li><li>Entitlements API shape <code>{ core, modules }</code>.</li></ol><p>For installations already on the modular-marketplace line: no additional intended API breaks in this tag.</p><hr><h2 id="upgrade-first-production-deploy" tabindex="-1">Upgrade / first production deploy <a class="header-anchor" href="#upgrade-first-production-deploy" aria-label="Permalink to &quot;Upgrade / first production deploy&quot;">​</a></h2><ol><li>Deploy Backend, Frontend, and Docs at tag <strong><code>v1.1.0</code></strong> (same intent across repos).</li><li>Follow <a href="/deployment/upgrade">Upgrade Guide</a> and <a href="/deployment/platform-production-runbook">Production Runbook</a>.</li><li>Complete Multi-Provider Email cutover (migrate, <code>email:migrate-tenant-mail-modes</code>, <code>queue:restart</code>).</li><li>Confirm queue workers listen on <code>emails,default</code>.</li><li>Do <strong>not</strong> run <code>db:seed</code> / catalog or permission seeders in production.</li></ol><hr><h2 id="testing-validation-gate-pre-tag-checklist" tabindex="-1">Testing / validation gate (pre-tag checklist) <a class="header-anchor" href="#testing-validation-gate-pre-tag-checklist" aria-label="Permalink to &quot;Testing / validation gate (pre-tag checklist)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gate</th><th>Target</th></tr></thead><tbody><tr><td>Backend Larastan</td><td><strong>0</strong> errors</td></tr><tr><td>Backend Pest</td><td>Full suite green</td></tr><tr><td>Backend Quality Gate + Laravel Tests</td><td>Green on <code>main</code></td></tr><tr><td>Frontend Quality Gate</td><td>Green on <code>main</code></td></tr><tr><td>Docs Quality Gate (VitePress + dead links)</td><td>Green on <code>main</code></td></tr><tr><td>Staging smoke</td><td>Central + Tenant auth, mail test, one Leads/Tasks path</td></tr></tbody></table><hr><h2 id="release-execution-order" tabindex="-1">Release execution order <a class="header-anchor" href="#release-execution-order" aria-label="Permalink to &quot;Release execution order&quot;">​</a></h2><ol><li>Merge Backend / Frontend / Docs stabilization PRs to <code>main</code></li><li>Confirm CI green on <code>main</code> for all three</li><li>Configure branch protection (admin) — see <a href="/deployment/release-process">Release Process</a></li><li>Tag each repo <code>v1.1.0</code> (Backend → Frontend → Docs)</li><li>Create GitHub Releases linking this page</li><li>Deploy and verify per runbook</li></ol><hr><h2 id="known-limitations" tabindex="-1">Known limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known limitations&quot;">​</a></h2><ul><li>Contacts / Companies / Calendar / Activities still planned (CRM roadmap)</li><li>Lead convert remains status-oriented until Contacts ships</li><li>Some Central Billing UI surfaces remain ledger/ops oriented</li></ul><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Historical freeze notes: <a href="/changelog/v1.1.0-platform">v1.1.0-platform (alias)</a></li><li><a href="/changelog/">CHANGELOG delivery notes</a></li><li><a href="/deployment/upgrade">Upgrade Guide</a></li><li><a href="/deployment/platform-production-runbook">Production Runbook</a></li><li><a href="/deployment/release-process">Release Process</a></li><li><a href="/developer-guide/documentation-governance">Documentation Governance</a></li><li><a href="/developer-guide/multi-provider-email">Multi-Provider Email</a></li></ul>',37)])])}const u=t(i,[["render",n]]);export{m as __pageData,u as default};
